60: /**
61:  * Determine whether the main entry point should be loaded through the ESM Loader.
62:  * @param {string} mainPath - Absolute path to the main entry point
63:  */
64: function shouldUseESMLoader(mainPath) {
65:   if (getOptionValue('--experimental-default-type') === 'module') { return true; }
66: 
67:   /**
68:    * @type {string[]} userLoaders A list of custom loaders registered by the user
69:    * (or an empty list when none have been registered).
70:    */
71:   const userLoaders = getOptionValue('--experimental-loader');
72:   /**
73:    * @type {string[]} userImports A list of preloaded modules registered by the user
74:    * (or an empty list when none have been registered).
75:    */
76:   const userImports = getOptionValue('--import');
77:   if (userLoaders.length > 0 || userImports.length > 0) { return true; }
78: 
79:   // Determine the module format of the entry point.
80:   if (mainPath && StringPrototypeEndsWith(mainPath, '.mjs')) { return true; }
81:   if (!mainPath || StringPrototypeEndsWith(mainPath, '.cjs')) { return false; }
82: 
83:   if (getOptionValue('--experimental-strip-types')) {
84:     // This ensures that --experimental-default-type=commonjs and .mts files are treated as commonjs
85:     if (getOptionValue('--experimental-default-type') === 'commonjs') { return false; }
86:     if (!mainPath || StringPrototypeEndsWith(mainPath, '.cts')) { return false; }
87:     // This will likely change in the future to start with commonjs loader by default
88:     if (mainPath && StringPrototypeEndsWith(mainPath, '.mts')) { return true; }
89:   }
90: 
91:   const type = getNearestParentPackageJSONType(mainPath);
92: 
93:   // No package.json or no `type` field.
94:   if (type === undefined || type === 'none') {
95:     return false;
96:   }
97: 
98:   return type === 'module';
99: }
